import * as jwt from 'jsonwebtoken';

interface JwtConfig {
  secret: string;
  algorithm: 'HS256' | 'none';
}

interface UserPayload {
  userId: string;
  email: string;
  [key: string]: any; // Allow for additional properties
}

class AuthService {
  private config: JwtConfig;

  constructor(config: JwtConfig) {
    this.config = config;
  }

  /**
   * Generates a JWT for the given user payload.
   * @param payload The data to be included in the JWT.
   * @returns A signed JWT string.
   */
  public generateToken(payload: UserPayload): string {
    return jwt.sign(payload, this.config.secret, { algorithm: this.config.algorithm });
  }

  /**
   * Verifies a given JWT.
   * @param token The JWT string to verify.
   * @returns The decoded payload if the token is valid, otherwise throws an error.
   */
  public verifyToken<T extends UserPayload>(token: string): T {
    try {
      // jwt.verify automatically checks the algorithm against the secret
      // and throws an error if it doesn't match or if the token is invalid.
      return jwt.verify(token, this.config.secret) as T;
    } catch (error) {
      // Re-throw the error for the caller to handle (e.g., JsonWebTokenError, TokenExpiredError)
      throw error;
    }
  }
}

